var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"…그래서 부상자 다수. 사망자는 민병대에 찍힌 알파트릭스 시큐리티의 임원 한 명이야.","JPN":"……で、怪我人多数。死亡者は民兵隊に狙われたアルファトリックスセキュリティの役員が一人。","ENG":"... so there were many who were injured, but the only one who died was Alphatrix's security director.","TWN":"…有多人受傷，死者只有一位，就是遭到民兵隊殺害的阿爾法崔克斯證券負責人。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"중상은 이 바보 한 명뿐이고.","JPN":"重傷はこのバカ一人だけ。","ENG":"And this idiot's the only one who was seriously injured.","TWN":"另外，重傷的就只有這個傻瓜。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"하하. 내가 통뼈라서 망정이지, 안 그랬으면 사망자가 한 명 더 늘어날 뻔했어.","JPN":"はは。俺の骨が丈夫でよかったぜ、じゃなけりゃあ死亡者が一人増えるところだったぞ。","ENG":"Haha. Just be glad I'm big-boned, or the death count would be two!","TWN":"哈哈，幸好我的骨骼驚奇，否則死亡人數可能要加一。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"으윽!?","JPN":"ううっ！？","ENG":"Ngh?!","TWN":"噢嗚！？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"입만 살았지, 이 화상아. 엄폐도 제대로 안 하고 정신없이 쏘기만 하니까 당하지.","JPN":"よく言うわ、このドアホ。物陰に隠れもしないで撃ちまくるからやられるのよ。","ENG":"Shut up! You're hurt because you kept shooting like a mad man without any cover!","TWN":"你就剩一張嘴是吧？也不找掩護，在那邊瘋狂掃射，當然會受傷。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오늘 총 잡아 본 풋내기들도 너처럼은 안 하겠다.","JPN":"初めて銃を持つ素人もあんたよりはマシだわ。","ENG":"Even rookies these days wouldn't act like you.","TWN":"就算是第一次拿槍的新手也不會像你這樣。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아니 그게, 그 파란 머리 아가씨에게 내버려 둘 수 없는 묘한 뭔가가 있었단 말이야.","JPN":"いや、それがな。あの青い髪のお嬢ちゃんにひっかかる妙な何かがあったんだ。","ENG":"But there was something odd about that blue-haired girl that I couldn't shake.","TWN":"不是，你聽我說，那個藍頭髮的小妹妹，我總覺得哪裡不對勁。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어떻게든 내 눈앞에서 치워야 한다거나……","JPN":"何としてでも俺の目の前から消さないといけないみたいな……","ENG":"As if something was telling me to kill it...","TWN":"不管怎麼樣一定要想辦法除掉她，否則後患無……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"으억!?","JPN":"うおっ！？","ENG":"Uargh?!","TWN":"噢嗚！？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"핑계 좀 지어대지 마, 핑계 좀. 오르카가 뭘 보고 배우겠어?","JPN":"言い訳はもういいよ、言い訳は。オルカが真似するでしょ。","ENG":"Enough of your excuses! What will Orca learn?","TWN":"少在那邊給我找理由，你這樣要怎麼教奧爾卡？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아니, 진짜 있었대도!","JPN":"いや、本当だって！","ENG":"I'm telling you the truth!","TWN":"吼唷，我是說真的啦！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"폭발이 일어났다는 뉴스는 저도 봤어요. 다행히 피해는 크지 않았나 보네요.","JPN":"爆発が起きたというニュースは私も見ました。幸い、被害は大きくはなかったようですね。","ENG":"I saw the news about the explosion being reported. Thank goodness the damages aren't that bad.","TWN":"我也有看到爆炸的新聞，幸好沒有造成太嚴重的傷亡。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 우리가 갔을 때는 직원들이 이미 방송 듣고 모두 내뺀 뒤였거든.","JPN":"まあ、俺たちが到着したときには、すでにアナウンス聞いて職員全員が逃げた後だったんだ。","ENG":"Well, the staff had already heard the news and evacuated the place by the time we got there.","TWN":"我們去的時候，大部分員工都已經聽到廣播進行疏散。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"의뢰주에게 잔금은 안 줘도 괜찮다고 했어. 혹시 시말서 필요하면 얘기해.","JPN":"依頼主に残金はいらないって話しておいたわ。もし始末書が必要だったら言って。","ENG":"I told our client that she won't have to pay the rest. Let me know if you need me to write up a statement letter.","TWN":"我已經跟委託人說不需要支付尾款，有需要提交報告的話再跟我說。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"민병대인가 하는 녀석들은 결국 놓쳤으니까.","JPN":"民兵隊とかいうやつらは結局捕まえられなかったから。","ENG":"Because we failed to catch the Militia.","TWN":"至於民兵隊的傢伙，結果還是沒逮到。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그 후줄근한 아저씨, 이럴 줄 알았으면 사채업자 만나러 갔을 때 잡는 거였는데.","JPN":"あのくたびれたおじさん、こうなると知ってたら闇金業者に会いに行ったときに捕まえておけばよかったわ。","ENG":"If I had known, I would've caught that hobo when I first saw him with that loan shark.","TWN":"早知道這樣，去找放高利貸的時候，就應該逮住那個邋遢大叔的。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 잘하셨어요. 두 분이 무리하셔야 할 만큼 저희 회사 자금 사정이……","JPN":"いいえ。十分です。お二人が無理しなければならないほど、会社の資金繰りが……","ENG":"No, you did a good job. The company is in such a bad financial situation that you two would have to...","TWN":"沒事的，你們做得很好。公司現在財政困難，只好讓你們二位這麼辛苦……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};